/**
 * CSS Bundle Loader - Generated by Master Build Optimizer
 * Efficiently loads CSS bundles based on page requirements
 */

class CSSBundleLoader {
  constructor() {
    this.bundles = {
      critical: '/styles/bundles/critical.css',
      main: '/styles/bundles/main.css',
      win95: '/styles/bundles/win95.css'
    };
    
    this.loadedBundles = new Set();
    this.loadingPromises = new Map();
  }

  /**
   * Load a specific CSS bundle
   * @param {string} bundleName - Name of the bundle to load
   * @returns {Promise} - Promise that resolves when bundle is loaded
   */
  async loadBundle(bundleName) {
    if (this.loadedBundles.has(bundleName)) {
      return Promise.resolve();
    }

    if (this.loadingPromises.has(bundleName)) {
      return this.loadingPromises.get(bundleName);
    }

    const bundleUrl = this.bundles[bundleName];
    if (!bundleUrl) {
      throw new Error(`Bundle '${bundleName}' not found`);
    }

    const loadPromise = new Promise((resolve, reject) => {
      const link = document.createElement('link');
      link.rel = 'stylesheet';
      link.href = bundleUrl;
      link.onload = () => {
        this.loadedBundles.add(bundleName);
        this.loadingPromises.delete(bundleName);
        resolve();
      };
      link.onerror = () => {
        this.loadingPromises.delete(bundleName);
        reject(new Error(`Failed to load CSS bundle: ${bundleName}`));
      };
      document.head.appendChild(link);
    });

    this.loadingPromises.set(bundleName, loadPromise);
    return loadPromise;
  }

  /**
   * Load multiple CSS bundles
   * @param {string[]} bundleNames - Array of bundle names to load
   * @returns {Promise} - Promise that resolves when all bundles are loaded
   */
  async loadBundles(bundleNames) {
    return Promise.all(bundleNames.map(name => this.loadBundle(name)));
  }

  /**
   * Load CSS bundles based on page type
   * @param {string} pageType - Type of page (home, nosytos95, etc.)
   */
  async loadForPage(pageType) {
    const pageConfigs = {
      home: ['critical', 'main'],
      nosytos95: ['critical', 'win95'],
      default: ['critical', 'main']
    };

    const bundles = pageConfigs[pageType] || pageConfigs.default;
    return this.loadBundles(bundles);
  }

  /**
   * Preload CSS bundles for better performance
   * @param {string[]} bundleNames - Array of bundle names to preload
   */
  preloadBundles(bundleNames) {
    bundleNames.forEach(bundleName => {
      const bundleUrl = this.bundles[bundleName];
      if (bundleUrl && !this.loadedBundles.has(bundleName)) {
        const link = document.createElement('link');
        link.rel = 'preload';
        link.as = 'style';
        link.href = bundleUrl;
        document.head.appendChild(link);
      }
    });
  }

  /**
   * Get loading status of bundles
   * @returns {Object} - Object with bundle loading status
   */
  getStatus() {
    return {
      loaded: Array.from(this.loadedBundles),
      loading: Array.from(this.loadingPromises.keys()),
      available: Object.keys(this.bundles)
    };
  }
}

// Create global instance
window.CSSBundleLoader = new CSSBundleLoader();

// Auto-load based on page detection
document.addEventListener('DOMContentLoaded', () => {
  const pageType = document.body.dataset.pageType || 'default';
  window.CSSBundleLoader.loadForPage(pageType);
});

// Export for module usage
if (typeof module !== 'undefined' && module.exports) {
  module.exports = CSSBundleLoader;
}
